const items = [];
const posts = $input.first().json.data.children;

for (const post of posts) {
  const data = post.data;
  const text = data.title + ' ' + (data.selftext || '');

  // Simple keyword matching for line mentions
  const lines = ['bakerloo', 'central', 'circle', 'district', 'dlr', 
    'elizabeth', 'hammersmith', 'jubilee', 'metropolitan', 'northern', 
    'piccadilly', 'victoria', 'waterloo', 'overground'];

  const textLower = text.toLowerCase();
  const lineMentioned = lines.find(line => textLower.includes(line)) || null;

  // Simple sentiment: count negative words
  const negativeWords = ['delay', 'delayed', 'cancelled', 'suspended', 
    'closure', 'closed', 'fault', 'failure', 'disruption', 'nightmare',
    'awful', 'terrible', 'stuck', 'stranded', 'broken'];
  const positiveWords = ['good', 'great', 'running', 'normal', 'fine', 
    'smooth', 'excellent', 'working'];

  let negCount = 0;
  let posCount = 0;
  for (const word of negativeWords) {
    if (textLower.includes(word)) negCount++;
  }
  for (const word of positiveWords) {
    if (textLower.includes(word)) posCount++;
  }

  // Score between -1 and 1
  const total = negCount + posCount;
  const sentiment = total === 0 ? 0 : (posCount - negCount) / total;

  // Extract matched keywords
  const allKeywords = [...negativeWords, ...positiveWords];
  const matched = allKeywords.filter(w => textLower.includes(w));

  items.push({
    json: {
      text_content: text.substring(0, 500),
      line_mentioned: lineMentioned,
      station_mentioned: null,
      sentiment_score: parseFloat(sentiment.toFixed(2)),
      keyword_tags: matched,
      source: 'reddit',
      timestamp: new Date(data.created * 1000).toISOString()
    }
  });
}

return items;
